{
  "name": "Cloud ROI & TCO Analyzer",
  "description": "A professional interactive dashboard to analyze Cloud Migration ROI vs On-Premises TCO, quantifying SLA downtime risks and financial impact."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Inputs {
  // Business Metrics
  revenuePerHour: number;

  // On-Prem Costs
  hardwareCost: number; // CapEx (Year 0)
  monthlyPowerCooling: number;
  monthlyBandwidth: number;
  adminCount: number;
  adminMonthlySalary: number;
  maintenanceYearlyRate: number; // % of hardware cost

  // Cloud Costs
  monthlyCloudBill: number;
  migrationCost: number; // One-time

  // Advanced / SLA
  onPremSla: number; // e.g., 99.5
  cloudSla: number; // e.g., 99.99
}

export interface YearData {
  year: number;
  onPremCumulative: number;
  cloudCumulative: number;
  onPremDowntimeCost: number;
  cloudDowntimeCost: number;
  savingsCumulative: number;
}

export interface SimulationResult {
  data: YearData[];
  totalSavings5Year: number;
  roi: number;
  breakEvenYear: number | null;
  slaBenefit5Year: number; // How much specifically saved due to uptime
}

import { Inputs, SimulationResult, YearData } from '../types';
import { HOURS_IN_YEAR } from '../constants';

export const calculateTCO = (inputs: Inputs): SimulationResult => {
  const years = 5;
  const data: YearData[] = [];

  // 1. Calculate SLA / Downtime Metrics
  const onPremDowntimeHours = HOURS_IN_YEAR * (1 - inputs.onPremSla / 100);
  const cloudDowntimeHours = HOURS_IN_YEAR * (1 - inputs.cloudSla / 100);

  const hourlyLaborCost = (inputs.adminMonthlySalary / 160) * inputs.adminCount;
  const downtimeCostPerHour = inputs.revenuePerHour + hourlyLaborCost;

  const onPremYearlyDowntimeCost = onPremDowntimeHours * downtimeCostPerHour;
  const cloudYearlyDowntimeCost = cloudDowntimeHours * downtimeCostPerHour;

  const slaBenefitYearly = onPremYearlyDowntimeCost - cloudYearlyDowntimeCost;

  // 2. Yearly Operational Costs
  const onPremOpEx = 
    (inputs.monthlyPowerCooling * 12) + 
    (inputs.monthlyBandwidth * 12) + 
    (inputs.adminMonthlySalary * 12 * inputs.adminCount) +
    (inputs.hardwareCost * (inputs.maintenanceYearlyRate / 100));

  const cloudOpEx = inputs.monthlyCloudBill * 12;

  let onPremCumulative = inputs.hardwareCost; // Year 0 CapEx
  let cloudCumulative = inputs.migrationCost; // Year 0 Migration Cost

  let breakEvenYear: number | null = null;

  for (let i = 1; i <= years; i++) {
    // Add OpEx + Downtime Risk
    onPremCumulative += onPremOpEx + onPremYearlyDowntimeCost;
    cloudCumulative += cloudOpEx + cloudYearlyDowntimeCost;

    if (breakEvenYear === null && cloudCumulative < onPremCumulative) {
      breakEvenYear = i;
    }

    data.push({
      year: i,
      onPremCumulative,
      cloudCumulative,
      onPremDowntimeCost: onPremYearlyDowntimeCost * i,
      cloudDowntimeCost: cloudYearlyDowntimeCost * i,
      savingsCumulative: onPremCumulative - cloudCumulative
    });
  }

  // 3. ROI Calculation
  // Total Benefit = (Cost OnPrem - Cost Cloud)
  // ROI = (Total Benefit - Investment) / Investment * 100
  // Where Investment is mainly Migration Cost + Initial Setup. 
  // However, the prompt defines ROI formula as:
  // ROI = (Total Savings + SLA Benefit - Migration Cost) / Migration Cost * 100%
  // *Note*: In our cumulative calculation, "Total Savings" already implicitly includes SLA benefit because OnPrem Cumulative includes the high downtime cost.

  const totalCostOnPrem = data[years - 1].onPremCumulative;
  const totalCostCloud = data[years - 1].cloudCumulative;
  const netSavings = totalCostOnPrem - totalCostCloud;

  // To strictly follow the prompt's implied logic of separating SLA:
  // We can treat "Savings" as just the Net financial difference.
  // Investment = Inputs.migrationCost (Assume this is the primary 'new' money spent to move).

  const roi = inputs.migrationCost > 0 
    ? (netSavings / inputs.migrationCost) * 100 
    : 0;

  return {
    data,
    totalSavings5Year: netSavings,
    roi,
    breakEvenYear,
    slaBenefit5Year: slaBenefitYearly * years
  };
};

export const formatCurrency = (val: number) => {
  return new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency: 'USD',
    maximumFractionDigits: 0,
    notation: "compact", 
    compactDisplay: "short"
  }).format(val);
};

export const formatCurrencyDetailed = (val: number) => {
  return new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency: 'USD',
    maximumFractionDigits: 0,
  }).format(val);
};

import React from 'react';
import { Info } from 'lucide-react';

interface InputSliderProps {
  label: string;
  value: number;
  onChange: (val: number) => void;
  min: number;
  max: number;
  step?: number;
  unit?: string;
  tooltip?: string;
  isPercentage?: boolean;
}

export const InputSlider: React.FC<InputSliderProps> = ({
  label,
  value,
  onChange,
  min,
  max,
  step = 1,
  unit = '$',
  tooltip,
  isPercentage = false,
}) => {
  return (
    <div className="mb-6">
      <div className="flex justify-between items-center mb-2">
        <div className="flex items-center gap-2 group relative">
          <label className="text-sm font-medium text-slate-300">{label}</label>
          {tooltip && (
            <>
              <Info className="w-4 h-4 text-slate-500 cursor-help" />
              <div className="absolute left-0 bottom-6 w-64 p-2 bg-slate-800 border border-slate-700 rounded shadow-xl text-xs text-slate-300 opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none z-50">
                {tooltip}
              </div>
            </>
          )}
        </div>
        <span className="text-sm font-bold text-indigo-400 font-mono">
          {isPercentage ? '' : unit}{isPercentage ? value.toFixed(2) : value.toLocaleString()}{isPercentage ? '%' : ''}
        </span>
      </div>
      <input
        type="range"
        min={min}
        max={max}
        step={step}
        value={value}
        onChange={(e) => onChange(Number(e.target.value))}
        className="w-full h-2 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-indigo-500 hover:accent-indigo-400 transition-colors"
      />
    </div>
  );
};

import React from 'react';
import { SimulationResult, Inputs } from '../types';
import { formatCurrencyDetailed } from '../utils/calculations';
import { FileText, TrendingUp, AlertTriangle, CheckCircle } from 'lucide-react';

interface ExecutiveSummaryProps {
  results: SimulationResult;
  inputs: Inputs;
}

export const ExecutiveSummary: React.FC<ExecutiveSummaryProps> = ({ results, inputs }) => {
  const yearlySlaBenefit = results.slaBenefit5Year / 5;
  const downtimeDiff = (inputs.cloudSla - inputs.onPremSla).toFixed(2);
  const isPositive = results.totalSavings5Year > 0;

  return (
    <div className="mt-8 bg-slate-900 border border-slate-700 rounded-xl overflow-hidden shadow-2xl">
      <div className="bg-slate-800/50 p-4 border-b border-slate-700 flex items-center gap-2">
        <FileText className="w-5 h-5 text-indigo-400" />
        <h3 className="font-semibold text-white">Executive Summary & High-Level Findings</h3>
      </div>

      <div className="p-6 grid gap-6 md:grid-cols-2 lg:grid-cols-3">
        {/* Key Takeaway 1: ROI */}
        <div className="space-y-3">
          <div className="flex items-center gap-2 text-emerald-400">
            <TrendingUp className="w-5 h-5" />
            <span className="font-bold uppercase text-xs tracking-wider">Financial Impact</span>
          </div>
          <p className="text-slate-300 text-sm leading-relaxed">
            Transitioning to the cloud is projected to generate a 5-year ROI of <span className="text-emerald-400 font-bold">{results.roi.toFixed(1)}%</span>. 
            The break-even point is estimated to occur in <span className="text-white font-bold">{results.breakEvenYear ? `Year ${results.breakEvenYear}` : 'Year 5+'}</span>.
          </p>
        </div>

        {/* Key Takeaway 2: SLA & Risk */}
        <div className="space-y-3">
          <div className="flex items-center gap-2 text-amber-400">
            <AlertTriangle className="w-5 h-5" />
            <span className="font-bold uppercase text-xs tracking-wider">Risk Mitigation (SLA)</span>
          </div>
          <p className="text-slate-300 text-sm leading-relaxed">
            By improving availability from {inputs.onPremSla}% to {inputs.cloudSla}% (+{downtimeDiff}%), 
            the business avoids an estimated <span className="text-amber-400 font-bold">{formatCurrencyDetailed(yearlySlaBenefit)}</span> in annual downtime losses 
            (Revenue + Emergency Labor).
          </p>
        </div>

        {/* Key Takeaway 3: Strategic */}
        <div className="space-y-3">
          <div className="flex items-center gap-2 text-blue-400">
            <CheckCircle className="w-5 h-5" />
            <span className="font-bold uppercase text-xs tracking-wider">Recommendation</span>
          </div>
          <p className="text-slate-300 text-sm leading-relaxed">
            {isPositive 
              ? "The analysis strongly supports a cloud migration strategy. The reduction in hardware CapEx and significant SLA risk mitigation outweighs the migration costs." 
              : "The analysis suggests a cautious approach. While SLA benefits are present, the high monthly cloud operational costs may require optimization (Reserved Instances/Savings Plans) to justify migration."}
          </p>
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { Inputs } from '../types';
import { InputSlider } from './ui/InputSlider';
import { Settings, Server, Cloud, DollarSign } from 'lucide-react';

interface InputPanelProps {
  inputs: Inputs;
  setInputs: React.Dispatch<React.SetStateAction<Inputs>>;
}

export const InputPanel: React.FC<InputPanelProps> = ({ inputs, setInputs }) => {
  const update = (key: keyof Inputs, val: number) => {
    setInputs(prev => ({ ...prev, [key]: val }));
  };

  return (
    <div className="space-y-8 pr-4">

      {/* Section 1: Business Value */}
      <section>
        <div className="flex items-center gap-2 mb-4 text-indigo-400">
          <DollarSign className="w-5 h-5" />
          <h3 className="font-bold uppercase text-xs tracking-widest">Business Value</h3>
        </div>
        <div className="bg-slate-900/50 p-4 rounded-xl border border-slate-800">
          <InputSlider
            label="Revenue Per Hour ($)"
            value={inputs.revenuePerHour}
            min={0}
            max={50000}
            step={500}
            onChange={(v) => update('revenuePerHour', v)}
            tooltip="Estimated revenue loss for every hour the system is down."
          />
        </div>
      </section>

      {/* Section 2: On-Premises Costs */}
      <section>
        <div className="flex items-center gap-2 mb-4 text-rose-400">
          <Server className="w-5 h-5" />
          <h3 className="font-bold uppercase text-xs tracking-widest">On-Premises (Current)</h3>
        </div>
        <div className="bg-slate-900/50 p-4 rounded-xl border border-slate-800">
          <InputSlider
            label="Hardware CapEx (Refresh)"
            value={inputs.hardwareCost}
            min={10000}
            max={1000000}
            step={5000}
            onChange={(v) => update('hardwareCost', v)}
            tooltip="Cost to buy/refresh servers, storage, and networking gear (Year 0)."
          />
          <InputSlider
            label="Monthly Power, Colo & Net"
            value={inputs.monthlyPowerCooling + inputs.monthlyBandwidth}
            min={100}
            max={20000}
            step={100}
            onChange={(v) => {
               // Split arbitrarily for simplicity in this combined slider, or just treat as OpEx
               const half = v/2;
               setInputs(prev => ({...prev, monthlyPowerCooling: half, monthlyBandwidth: half }));
            }}
            tooltip="Recurring monthly costs for rack space, power, cooling, and bandwidth."
          />
          <InputSlider
            label="IT Staff Count"
            value={inputs.adminCount}
            min={0}
            max={20}
            step={1}
            unit=""
            onChange={(v) => update('adminCount', v)}
            tooltip="Number of Full-Time Employees managing the infrastructure."
          />
          <InputSlider
            label="Avg Monthly Salary"
            value={inputs.adminMonthlySalary}
            min={2000}
            max={20000}
            step={500}
            onChange={(v) => update('adminMonthlySalary', v)}
            tooltip="Fully loaded monthly cost per IT staff member."
          />
          <InputSlider
            label="SLA / Uptime (%)"
            value={inputs.onPremSla}
            min={90}
            max={99.9}
            step={0.1}
            isPercentage
            onChange={(v) => update('onPremSla', v)}
            tooltip="Current historical availability. 99.5% = ~44 hours downtime/year."
          />
        </div>
      </section>

      {/* Section 3: Cloud Costs */}
      <section>
        <div className="flex items-center gap-2 mb-4 text-emerald-400">
          <Cloud className="w-5 h-5" />
          <h3 className="font-bold uppercase text-xs tracking-widest">Cloud Target</h3>
        </div>
        <div className="bg-slate-900/50 p-4 rounded-xl border border-slate-800">
          <InputSlider
            label="Est. Monthly Cloud Bill"
            value={inputs.monthlyCloudBill}
            min={100}
            max={50000}
            step={500}
            onChange={(v) => update('monthlyCloudBill', v)}
            tooltip="Projected costs for Compute, Storage, and Managed Services."
          />
          <InputSlider
            label="One-time Migration Cost"
            value={inputs.migrationCost}
            min={0}
            max={200000}
            step={1000}
            onChange={(v) => update('migrationCost', v)}
            tooltip="Professional services, training, and parallel run costs."
          />
          <InputSlider
            label="Target SLA (%)"
            value={inputs.cloudSla}
            min={99}
            max={99.999}
            step={0.001}
            isPercentage
            onChange={(v) => update('cloudSla', v)}
            tooltip="Target availability. 99.99% = ~52 mins downtime/year."
          />
        </div>
      </section>

    </div>
  );
};

import React from 'react';
import { 
  LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer,
  PieChart, Pie, Cell
} from 'recharts';
import { SimulationResult, Inputs } from '../types';
import { formatCurrency, formatCurrencyDetailed } from '../utils/calculations';
import { ArrowUpRight, ArrowDownRight, ShieldCheck } from 'lucide-react';

interface DashboardProps {
  results: SimulationResult;
  inputs: Inputs;
}

const COLORS = ['#f43f5e', '#10b981', '#6366f1', '#f59e0b'];

export const Dashboard: React.FC<DashboardProps> = ({ results, inputs }) => {

  // Prepare data for Pie Chart (Components of Savings)
  // We want to show what makes up the "Value" of Cloud.
  // 1. Hardware Avoidance (OnPrem CapEx + Maint)
  // 2. SLA Risk Avoidance (The difference in downtime cost)
  // 3. Operational Labor Savings (assuming Cloud needs less labor - usually true, but inputs dictate this. 
  //    For visualization, we'll calculate the difference in 5-year OpEx minus Cloud Bill).

  const totalOnPremCost = results.data[4].onPremCumulative;
  const totalCloudCost = results.data[4].cloudCumulative;

  const slaSavings = results.slaBenefit5Year;
  const rawCostSavings = (totalOnPremCost - slaSavings) - (totalCloudCost); // Pure OpEx/CapEx difference

  const pieData = [
    { name: 'SLA Risk Avoidance', value: slaSavings > 0 ? slaSavings : 0 },
    { name: 'Infra & Ops Savings', value: rawCostSavings > 0 ? rawCostSavings : 0 },
  ].filter(d => d.value > 0);

  // If Cloud is actually more expensive, we show Cost Distribution instead
  const isCloudMoreExpensive = results.totalSavings5Year < 0;

  return (
    <div className="space-y-6">

      {/* Top Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className="bg-slate-800 p-6 rounded-xl border border-slate-700 relative overflow-hidden">
          <div className="absolute top-0 right-0 p-3 opacity-10">
            <ShieldCheck size={64} />
          </div>
          <p className="text-slate-400 text-sm font-medium mb-1">5-Year Net Savings</p>
          <h2 className={`text-3xl font-bold ${results.totalSavings5Year >= 0 ? 'text-emerald-400' : 'text-rose-400'}`}>
            {formatCurrencyDetailed(results.totalSavings5Year)}
          </h2>
          <div className="flex items-center gap-1 mt-2 text-xs text-slate-500">
            {results.totalSavings5Year >= 0 ? <ArrowUpRight size={14} /> : <ArrowDownRight size={14} />}
            <span>vs On-Premises Baseline</span>
          </div>
        </div>

        <div className="bg-slate-800 p-6 rounded-xl border border-slate-700">
           <p className="text-slate-400 text-sm font-medium mb-1">Return on Investment (ROI)</p>
           <h2 className="text-3xl font-bold text-indigo-400">{results.roi.toFixed(1)}%</h2>
           <p className="text-xs text-slate-500 mt-2">Break-even: {results.breakEvenYear ? `Year ${results.breakEvenYear}` : 'N/A'}</p>
        </div>

        <div className="bg-slate-800 p-6 rounded-xl border border-slate-700">
           <p className="text-slate-400 text-sm font-medium mb-1">SLA Risk Mitigated</p>
           <h2 className="text-3xl font-bold text-amber-400">{formatCurrencyDetailed(results.slaBenefit5Year)}</h2>
           <p className="text-xs text-slate-500 mt-2">Over 5 years due to higher uptime</p>
        </div>
      </div>

      {/* Charts Row */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

        {/* Main Line Chart */}
        <div className="lg:col-span-2 bg-slate-900 border border-slate-800 rounded-xl p-6 shadow-sm">
          <h3 className="text-lg font-semibold text-white mb-6">Cumulative TCO Analysis (5 Years)</h3>
          <div className="h-[350px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <LineChart data={results.data} margin={{ top: 5, right: 30, left: 20, bottom: 5 }}>
                <CartesianGrid strokeDasharray="3 3" stroke="#334155" opacity={0.5} />
                <XAxis 
                  dataKey="year" 
                  stroke="#94a3b8" 
                  tickFormatter={(val) => `Year ${val}`} 
                />
                <YAxis 
                  stroke="#94a3b8" 
                  tickFormatter={(val) => formatCurrency(val)} 
                  width={60}
                />
                <Tooltip 
                  contentStyle={{ backgroundColor: '#1e293b', borderColor: '#334155', color: '#f1f5f9' }}
                  formatter={(val: number) => formatCurrencyDetailed(val)}
                  labelStyle={{ color: '#94a3b8' }}
                />
                <Legend wrapperStyle={{ paddingTop: '20px' }} />
                <Line 
                  type="monotone" 
                  dataKey="onPremCumulative" 
                  name="On-Premises (Cumulative)" 
                  stroke="#f43f5e" 
                  strokeWidth={3} 
                  dot={{ r: 4 }} 
                  activeDot={{ r: 8 }} 
                />
                <Line 
                  type="monotone" 
                  dataKey="cloudCumulative" 
                  name="Business on Cloud (Cumulative)" 
                  stroke="#10b981" 
                  strokeWidth={3} 
                  dot={{ r: 4 }} 
                  activeDot={{ r: 8 }} 
                />
              </LineChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Pie Chart / Breakdown */}
        <div className="bg-slate-900 border border-slate-800 rounded-xl p-6 shadow-sm flex flex-col">
          <h3 className="text-lg font-semibold text-white mb-2">
            {isCloudMoreExpensive ? "Cloud Cost Drivers" : "Savings Composition"}
          </h3>
          <p className="text-xs text-slate-400 mb-6">
             {isCloudMoreExpensive 
              ? "Cloud TCO is currently higher than On-Prem. Review monthly spend." 
              : "Breakdown of where the value comes from."}
          </p>

          <div className="flex-1 min-h-[250px] relative">
            {isCloudMoreExpensive ? (
              <div className="flex items-center justify-center h-full text-slate-500 italic text-sm text-center px-8">
                Break-even not reached within 5 years based on current parameters.
              </div>
            ) : (
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie
                    data={pieData}
                    cx="50%"
                    cy="50%"
                    innerRadius={60}
                    outerRadius={80}
                    paddingAngle={5}
                    dataKey="value"
                  >
                    {pieData.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={index === 0 ? '#f59e0b' : '#10b981'} />
                    ))}
                  </Pie>
                  <Tooltip 
                    formatter={(val: number) => formatCurrencyDetailed(val)}
                    contentStyle={{ backgroundColor: '#1e293b', borderColor: '#334155', color: '#f1f5f9' }}
                  />
                  <Legend verticalAlign="bottom" height={36}/>
                </PieChart>
              </ResponsiveContainer>
            )}
          </div>
        </div>
      </div>

    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { DEFAULT_INPUTS } from './constants';
import { Inputs, SimulationResult } from './types';
import { calculateTCO } from './utils/calculations';
import { InputPanel } from './components/InputPanel';
import { Dashboard } from './components/Dashboard';
import { ExecutiveSummary } from './components/ExecutiveSummary';
import { Activity } from 'lucide-react';

const App: React.FC = () => {
  const [inputs, setInputs] = useState<Inputs>(DEFAULT_INPUTS);
  const [results, setResults] = useState<SimulationResult>(calculateTCO(DEFAULT_INPUTS));

  // Recalculate whenever inputs change
  useEffect(() => {
    setResults(calculateTCO(inputs));
  }, [inputs]);

  return (
    <div className="min-h-screen bg-slate-950 text-slate-200 font-sans selection:bg-indigo-500/30">

      {/* Header */}
      <header className="sticky top-0 z-40 w-full backdrop-blur-lg bg-slate-950/80 border-b border-slate-800">
        <div className="container mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-600 p-2 rounded-lg">
              <Activity className="w-5 h-5 text-white" />
            </div>
            <div>
              <h1 className="font-bold text-lg tracking-tight text-white">CloudArchitect<span className="text-indigo-400">.ai</span></h1>
              <p className="text-[10px] text-slate-400 uppercase tracking-widest font-semibold">TCO & ROI Simulator</p>
            </div>
          </div>
          <div className="hidden md:block">
            <span className="inline-flex items-center rounded-full bg-slate-800 px-3 py-1 text-xs font-medium text-slate-400 ring-1 ring-inset ring-slate-700">
              v2.4.0 (Enterprise)
            </span>
          </div>
        </div>
      </header>

      <main className="container mx-auto px-4 py-8">
        <div className="grid grid-cols-1 xl:grid-cols-12 gap-8">

          {/* Left Sidebar: Controls */}
          <div className="xl:col-span-3 xl:border-r xl:border-slate-800/50 xl:pr-6 h-fit overflow-y-auto max-h-[calc(100vh-6rem)] custom-scrollbar">
             <div className="mb-6">
                <h2 className="text-lg font-semibold text-white">Parameters</h2>
                <p className="text-sm text-slate-500">Adjust detailed cost drivers below.</p>
             </div>
             <InputPanel inputs={inputs} setInputs={setInputs} />
          </div>

          {/* Right Content: Visualization */}
          <div className="xl:col-span-9 space-y-8">
            <Dashboard results={results} inputs={inputs} />
            <ExecutiveSummary results={results} inputs={inputs} />
          </div>

        </div>
      </main>

      <footer className="border-t border-slate-900 mt-12 py-8 text-center text-slate-600 text-sm">
        <p>&copy; {new Date().getFullYear()} Cloud Architect Consulting. Generated for strategic analysis.</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { DEFAULT_INPUTS } from './constants';
import { Inputs, SimulationResult } from './types';
import { calculateTCO } from './utils/calculations';
import { InputPanel } from './components/InputPanel';
import { Dashboard } from './components/Dashboard';
import { ExecutiveSummary } from './components/ExecutiveSummary';
import { Activity } from 'lucide-react';

