        </div>

        <div className="bg-slate-800 p-6 rounded-xl border border-slate-700">
           <p className="text-slate-400 text-sm font-medium mb-1">投资回报率 (ROI)</p>
           <h2 className="text-3xl font-bold text-indigo-400">{results.roi.toFixed(1)}%</h2>
           <p className="text-xs text-slate-500 mt-2">盈亏平衡: {results.breakEvenYear ? `第 ${results.breakEvenYear} 年` : '未达成'}</p>
        </div>

        <div className="bg-slate-800 p-6 rounded-xl border border-slate-700">
           <p className="text-slate-400 text-sm font-medium mb-1">SLA 风险规避价值</p>
