import React from 'react';
import { Info } from 'lucide-react';

interface InputSliderProps {
  label: string;
  value: number;
  onChange: (val: number) => void;
  min: number;
  max: number;
  step?: number;
  unit?: string;
  tooltip?: string;
  isPercentage?: boolean;
}

export const InputSlider: React.FC<InputSliderProps> = ({
  label,
  value,
  onChange,
  min,
  max,
  step = 1,
  unit = '¥',
  tooltip,
  isPercentage = false,
}) => {

  // Handle manual text input changes
  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    // If empty string (user clearing input), default to 0 to prevent NaN errors
    const val = e.target.value === '' ? 0 : parseFloat(e.target.value);
    onChange(val);
  };

  return (
    <div className="mb-6">
      <div className="flex justify-between items-center mb-2">
        {/* Label & Tooltip */}
        <div className="flex items-center gap-2 group relative">
          <label className="text-sm font-medium text-slate-300">{label}</label>
          {tooltip && (
            <>
              <Info className="w-4 h-4 text-slate-500 cursor-help" />
              <div className="absolute left-0 bottom-6 w-64 p-2 bg-slate-800 border border-slate-700 rounded shadow-xl text-xs text-slate-300 opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none z-50">
                {tooltip}
              </div>
            </>
          )}
        </div>

        {/* Manual Input Field */}
        <div className="flex items-center bg-slate-900/50 border border-slate-700 rounded-md focus-within:border-indigo-500 focus-within:ring-1 focus-within:ring-indigo-500/50 transition-all w-32 px-2">
          {!isPercentage && unit && (
            <span className="text-slate-500 text-xs font-mono mr-1 select-none">{unit}</span>
          )}
          <input
            type="number"
            min={min}
            max={max}
            step="any" 
            value={value}
            onChange={handleInputChange}
            className="w-full bg-transparent text-right text-indigo-400 font-mono text-sm font-bold focus:outline-none py-1 appearance-none [&::-webkit-inner-spin-button]:appearance-none [&::-webkit-outer-spin-button]:appearance-none"
          />
          {isPercentage && (
            <span className="text-slate-500 text-xs font-mono ml-1 select-none">%</span>
          )}
        </div>
      </div>

      {/* Range Slider */}
      <input
        type="range"
        min={min}
        max={max}
        step={step}
        value={value}
        onChange={(e) => onChange(Number(e.target.value))}
        className="w-full h-2 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-indigo-500 hover:accent-indigo-400 transition-colors focus:outline-none focus:ring-2 focus:ring-indigo-500/30"
      />
    </div>
  );
};

