              </div>
              <ul className="list-disc pl-3 space-y-1.5 text-slate-300">
                <li>
                  <strong className="text-emerald-400/80">本地TCO:</strong> 硬件CapEx + 5年运维(电力/带宽/薪资/维保) + 5年宕机损失
                </li>
                <li>
                  <strong className="text-rose-400/80">云端TCO:</strong> 迁移费 + 5年云账单 + 5年宕机损失
                </li>
              </ul>
            </MetricTooltip>
          </div>
          <h2 className={`text-3xl font-bold ${results.totalSavings5Year >= 0 ? 'text-emerald-600' : 'text-rose-600'}`}>
            {formatCurrencyDetailed(results.totalSavings5Year)}
          </h2>
          <div className="flex items-center gap-1 mt-2 text-xs text-slate-500">
            {results.totalSavings5Year >= 0 ? <ArrowUpRight size={14} /> : <ArrowDownRight size={14} />}
            <span>含 SLA 风险规避价值</span>
          </div>
        </div>

        {/* Card 2: ROI */}
