        </div>

        {/* Pie Chart / Breakdown */}
        <div className="bg-white border border-slate-200 rounded-xl p-6 shadow-sm flex flex-col z-0">
          <h3 className="text-lg font-semibold text-slate-900 mb-2">
            {isCloudMoreExpensive ? "云成本构成" : "总价值构成分析"}
